<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Ubuntu Desktop</title>
  <style>
    * { box-sizing: border-box; }
    body, #desktop {
      margin: 0;
      width: 100vw;
      height: 100vh;
      overflow: hidden;
      font-family: sans-serif;
    }
    #taskbar {
      position: fixed;
      bottom: 0;
      left: 0;
      right: 0;
      background-color: #2a2a2a;
      color: white;
      display: flex;
      padding: 10px;
      gap: 10px;
    }
    .window {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      background-color: #333;
      color: white;
      display: none;
      width: 400px;
      min-width: 360px;
      min-height: 280px;
    }
    .title-bar {
      padding: 10px;
      background-color: #1e1e1e;
      cursor: move;
    }
    .win-close {
      float: right;
      background: none;
      border: none;
      color: white;
      font-size: 16px;
      cursor: pointer;
    }
    .fs-item {
      padding: 5px;
      margin: 2px 0;
      background-color: #444;
      cursor: pointer;
    }
    #files-list {
      list-style-type: none;
      padding-left: 0;
    }
    .tab {
      display: inline-block;
      padding: 5px 10px;
      margin-right: 5px;
      background-color: #444;
      cursor: pointer;
    }
    .tab.active {
      background-color: #666;
    }
    #editor {
      width: 100%;
      height: 80%;
      font-family: monospace;
      resize: none;
    }
  </style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <button id="open-files">Files</button>
    <button id="open-notepad">Notepad</button>
  </div>

  <div id="files-window" class="window">
    <div class="title-bar"><span>Files</span><button class="win-close">&times;</button></div>
    <div class="content">
      <div id="files-path">/</div>
      <button id="files-up">Up</button>
      <ul id="files-list"></ul>
    </div>
  </div>

  <div id="notepad-window" class="window">
    <div class="title-bar"><span>Notepad</span><button class="win-close">&times;</button></div>
    <div class="content">
      <div id="tabs"></div>
      <button id="new-tab">New Tab</button>
      <textarea id="editor"></textarea>
    </div>
  </div>
</div>

<script>
const fakeFs = {
  '/': ['bin', 'etc', 'home', 'usr', 'var'],
  '/bin': [],
  '/etc': [],
  '/home': ['user'],
  '/home/user': ['Documents', 'Downloads', 'Pictures', 'file1.txt', 'file2.txt'],
  '/usr': [],
  '/var': []
};

let currentPath = '/';

function renderFiles() {
  const filesList = document.getElementById('files-list');
  filesList.innerHTML = '';
  const items = fakeFs[currentPath] || [];
  items.forEach(item => {
    const itemEl = document.createElement('div');
    itemEl.className = 'fs-item';
    itemEl.textContent = item;
    const isDir = fakeFs[`${currentPath}${item}/`] !== undefined;
    if (isDir) itemEl.style.fontWeight = 'bold';
    itemEl.addEventListener('dblclick', () => {
      if (isDir) {
        currentPath += item + '/';
        document.getElementById('files-path').textContent = currentPath;
        renderFiles();
      }
    });
    filesList.appendChild(itemEl);
  });
}

document.getElementById('files-up').addEventListener('click', () => {
  if (currentPath !== '/') {
    const parts = currentPath.split('/');
    parts.pop();
    currentPath = parts.join('/') + '/';
    document.getElementById('files-path').textContent = currentPath;
    renderFiles();
  }
});

let tabsData = JSON.parse(localStorage.getItem('notepad-tabs')) || [{ title: 'Untitled', content: '' }];
let activeTabIndex = 0;

function renderTabs() {
  const tabsContainer = document.getElementById('tabs');
  tabsContainer.innerHTML = '';
  tabsData.forEach((tab, index) => {
    const tabEl = document.createElement('div');
    tabEl.className = 'tab';
    tabEl.textContent = tab.title;
    if (index === activeTabIndex) tabEl.classList.add('active');
    tabEl.addEventListener('click', () => {
      activeTabIndex = index;
      renderTabs();
      document.getElementById('editor').value = tabsData[index].content;
    });
    tabsContainer.appendChild(tabEl);
  });
}

document.getElementById('new-tab').addEventListener('click', () => {
  const newTab = { title: 'Untitled', content: '' };
  tabsData.push(newTab);
  activeTabIndex = tabsData.length - 1;
  renderTabs();
  document.getElementById('editor').value = '';
});

document.getElementById('editor').addEventListener('input', (e) => {
  if (activeTabIndex < tabsData.length) {
    tabsData[activeTabIndex].content = e.target.value;
    localStorage.setItem('notepad-tabs', JSON.stringify(tabsData));
  }
});

function makeDraggable(el) {
  const titleBar = el.querySelector('.title-bar');
  let isDragging = false, offsetX, offsetY;

  titleBar.addEventListener('mousedown', (e) => {
    isDragging = true;
    offsetX = e.clientX - el.offsetLeft;
    offsetY = e.clientY - el.offsetTop;
    document.body.style.cursor = 'grabbing';
  });

  document.addEventListener('mousemove', (e) => {
    if (!isDragging) return;
    const x = e.clientX - offsetX;
    const y = e.clientY - offsetY;
    el.style.left = `${x}px`;
    el.style.top = `${y}px`;
  });

  document.addEventListener('mouseup', () => {
    isDragging = false;
    document.body.style.cursor = 'default';
  });
}

document.querySelectorAll('.window').forEach(win => makeDraggable(win));

document.getElementById('open-files').addEventListener('click', () => {
  const win = document.getElementById('files-window');
  win.style.display = 'block';
  if (win.querySelector('#files-list').children.length === 0) renderFiles();
});

document.getElementById('open-notepad').addEventListener('click', () => {
  const win = document.getElementById('notepad-window');
  win.style.display = 'block';
  renderTabs();
  document.getElementById('editor').value = tabsData[activeTabIndex].content;
});

document.querySelectorAll('.win-close').forEach(btn => {
  btn.addEventListener('click', function() {
    this.closest('.window').style.display = 'none';
  });
});
</script>
</body>
</html>
